var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"여인이 처음 눈을 뜬 날은 적막한 밤을 눈이 지워 내리는 겨울날이었다.","JPN":"女性が初めて目覚めたのは、寂寞たる夜を雪が消すように降る冬の日だった。","ENG":"The day the woman first opened her eyes was a winter night, where snow fell and erased all sound.","TWN":"女子第一次睜開眼睛的那天，是一個寂靜的夜晚，雪花飄落的冬日。"},"stage":{"bg":"MS_1118","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"이성과 고통마저 하얗게 염하여 세상을 원망하고, 삶의 자취를 지워가는 세상.","JPN":"理性と苦痛さえも白く塗りつぶされ、現実を恨み、生の痕跡が消えてゆく世界。","ENG":"A world that cursed life, bleaching away even reason and pain, erasing all trace of existence.","TWN":"連理智和痛苦都被白色染盡，怨恨著世界，抹去生活痕跡的世界。"},"stage":{"bg":"MS_1118","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"그녀는 차디찬 고독이 죽음보다 두려운 것을 알고 있음에.","JPN":"冷たい孤独が死よりも恐ろしいということをわかっていた彼女は……","ENG":"She knew that bitter solitude could be more terrifying than death.","TWN":"她知道冰冷的孤獨比死亡更可怕。"},"stage":{"bg":"MS_1118","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"긴 겨울이 끝나고, 언젠가 봄이 오기를 바라며 열두 개의 별을 하늘에 새겼다.","JPN":"長い冬の果てにいつか春が来ることを祈り、12の星を空に刻んだ。","ENG":"Hoping spring would come after the long winter, she carved twelve stars into the sky.","TWN":"漫長的冬天結束後，期待著有一天春天會到來，於是在天空中刻下了十二顆星星。"},"stage":{"bg":"MS_1118","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"narration","speaker":null,"text":{"KOREA":"먼 훗날. 멸망을 목도한 아이들이 길을 잃었을 때.","JPN":"遠い未来、滅びを迎えた子どもたちが道に迷った時。","ENG":"So that one day, when the children who witnessed the world's ruin lost their way...","TWN":"遙遠的未來。當目睹毀滅的孩子們迷失方向時。"},"stage":{"bg":"MS_1119","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"narration","speaker":null,"text":{"KOREA":"그녀가 새긴 별빛이, 그들을 구원의 길로 인도하길 바라며.","JPN":"彼女が刻んだ星の光が、彼らを救いへと導いてくれることを願って。","ENG":"They might find salvation, guided by that starlight.","TWN":"願她留下的星光，引導他們走向救贖之路。"},"stage":{"bg":"MS_1119","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRIESTESS_NPC_NULL_NULL","text":{"KOREA":"그대들의 주인은 오직 고통받는 이들일지니, 비통한 목소리를 대신하여 이 영광된 의식을 거행한다.","JPN":"そなたたちの主は苦しみに満ちた者たちのみ。悲痛な声に代わり、この栄光なる儀式を執り行おう。","ENG":"You serve no one but the afflicted. I hereby officiate this honorable ceremony on behalf of everyone who's suffering.","TWN":"你們的主人即是受苦的弱者。在此，我將代替那些悲痛的聲音，舉行這光榮的儀式。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PRIESTESS_NPC_NULL_NULL","text":{"KOREA":"제국의 광명을 따라 만인을 지키기로 맹세할 자, 누구인가?","JPN":"帝国の光明に従い、万人を守ると誓う者は誰だ。","ENG":"Who pledges today to follow the Empire's light and protect humanity?","TWN":"誰願意追隨帝國的光明，守護萬民？"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"레이. 정의로운 별의 인도로 이 자리에 섰습니다.","JPN":"レイ、正義なる星の導きよりこの場に辿り着きました。","ENG":"I, Ray, stand here under the guidance of the righteous Stars.","TWN":"我，雷伊，受正義之星之引導而站在此處。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PRIESTESS_NPC_NULL_NULL","text":{"KOREA":"그대는 구원의 이름을 내걸어 무엇을 맹세하겠는가?","JPN":"そなたは救いの名のもとに何を誓うか。","ENG":"What do you pledge in name of the salvation?","TWN":"你要以救贖之名許下何種誓言？"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"적막한 밤의 평화. 별처럼 빛나는 희망.","JPN":"寂寞たる夜の平和。星のごとく光る希望。","ENG":"The peace of a quiet night. Hope that shines like the stars.","TWN":"長夜寂靜，和平永存，群星閃耀，希望尤在。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"아스라이 스러진 별들이 보지 못한 제국의 새벽을 되찾으리라는 믿음을 맹세합니다.","JPN":"儚く消えていった星たちが見届けなかった、帝国の夜明けを取り戻すと信じる心を誓います。","ENG":"I swear to reclaim the dawn of the Empire that the fallen stars never saw.","TWN":"我發誓要找回那些未曾見過帝國黎明的星辰的信念。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PRIESTESS_NPC_NULL_NULL","text":{"KOREA":"별의 인도자를 대신하여, 나 제국의 대신전장이 이 자리에서 선언한다.","JPN":"星の導き手に代わり、帝国の大神殿長がこの場をもって宣言する。","ENG":"In place of the Star Guide, I, Chief Minister of the Empire, hereby proclaim it.","TWN":"代表星之引導者，帝國的大神殿長在此宣告。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PRIESTESS_NPC_NULL_NULL","text":{"KOREA":"위대한 제국 아르카데나는 이를 말미암아 구원의 맹세에 따를 지어다.","JPN":"偉大なる帝国アルカデナは、これをもって救いの誓いに従うと。","ENG":"Let the great Empire of Arcadena henceforth abide by this vow of salvation.","TWN":"偉大的艾爾卡特納帝國因此將遵循救贖的誓言。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"하아… 기, 긴장했다…….","JPN":"はあ……き、緊張した……","ENG":"Phew... Th-that was nerve-racking...","TWN":"哈啊…我，有點緊張了……"},"stage":{"bg":"CASTLE_02","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"능청스러운 태도로 단상에 서더니. 내려오자마자 이런 꼴인가.","JPN":"飄々と壇上に立ったかと思えば、降りるなりこの様とは。","ENG":"You stood there acting so confident, and now look at you.","TWN":"在講臺上那麼傲慢。一下來就這副模樣嗎?"},"stage":{"bg":"CASTLE_02","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"우스꽝스럽지만 합격점이다.","JPN":"滑稽ではあるが、及第点だ。","ENG":"Ridiculous, but passable.","TWN":"雖然有些滑稽，但還算合格。"},"stage":{"bg":"CASTLE_02","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"구원자의 이름을 내걸었다면, 그 또한 그대가 짊어져야 할 의무 중 하나겠지.","JPN":"救世主の名を掲げたのなら、それもまた、貴様が背負うべき義務の一つだろう。","ENG":"If you’ve taken up the name of the Savior, then that too must be one of the duties you bear.","TWN":"既然以救贖主之名行事，那這也是你必須承擔的責任之一吧。"},"stage":{"bg":"CASTLE_02","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"감사합니다, 전하. 그래도 이정도로 많은 분들이 오실 줄은 몰랐어요.","JPN":"ありがとうございます、殿下。でも、こんなにたくさんの人が来るとは思いませんでした。","ENG":"Thank you, Your Highness. Still, I didn't expect this many people to come.","TWN":"謝謝，殿下。不過我沒想到會有這麼多人來。"},"stage":{"bg":"CASTLE_02","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_LAUGH"}}}},{"id":"L34_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"이백 년 만에 나타난 구원자가 평민 출신인 것도 모자라 노예 출신 성녀를 지목해버렸으니 말이다.","JPN":"200年ぶりに現れた救世主が平民の出であるばかりか、奴隷出身の者を聖女に指名したのだからな。","ENG":"It's not enough that the first Savior in two hundred years is a commoner, he also named a former slave as the Saintess, too.","TWN":"兩百年來首次出現的救贖主不僅是平民出身，還指名一位出身奴隸的人為聖女。"},"stage":{"bg":"CASTLE_02","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"성유물의 판단이 있었다 한들 여론을 잠재우려면 확실히 못을 박아야겠지.\xA0\xA0","JPN":"たとえ聖遺物の判断があったとはいえ、世論を鎮めるには釘を刺しておいたほうがいいだろう。\xA0\xA0","ENG":"Even with the Holy Relic's judgment, we needed something decisive to quiet public opinion.\xA0\xA0","TWN":"即便有聖遺物的判斷，要平息輿論還是得明確表態。\xA0\xA0"},"stage":{"bg":"CASTLE_02","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"황실에 이어 신민들의 지지 또한 견고히 다졌으니, 다른 귀족들도 함부로 나설 순 없을 거다.","JPN":"皇室に続き、臣民の支持も固めた以上、他の貴族どもも軽々しく動くことはできまい。","ENG":"Now that the Crown and the people are on your side, the nobles won't dare make a move.","TWN":"繼皇室之後，臣民的支持也得到了鞏固，其他貴族也無法輕舉妄動。"},"stage":{"bg":"CASTLE_02","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"예. 구원자님께 흑색제복이 건네지는 것을 만민이 보았으니, 설령 교회라고 한들 선택을 번복할 수 없을 겁니다.","JPN":"はい。救世主様に黒い礼装が手渡される場面を万民が目にしたのですから、たとえ教会でも、選択を覆すことはできないはずです。","ENG":"Yes. Everyone saw the Savior receive the black uniform. Not even the Church can reverse that.","TWN":"是的。救贖主大人穿上黑色制服的情景眾人皆見，即便是教會也無法更改這個選擇。"},"stage":{"bg":"CASTLE_02","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"흑색제복… 분명 제국에 내려져 오는 별의 인도자의 무구 중 하나였죠.","JPN":"黒い礼装……確か、帝国に受け継がれてきた、星の導き手の武具の一つ、でしたよね？","ENG":"The black uniform... That's one of the Star Guide's Armament, passed down in the Empire, right?","TWN":"黑色制服……確實是帝國傳承下來的星之引導者的武具之一。"},"stage":{"bg":"CASTLE_02","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};